formulaRecommendations.pseudoFormula:
BCR = ComponentVariable / ComponentQuota;
Attainment = ActualBookings / ComponentQuota;
Payout = SUM_OVER_TIERS(MIN(ActualBookings, TierMax*Quota) - MAX(0, TierMin*Quota)) * BCR * TierMultiplier;

Floor = 2*TargetRetentionRate - 1;
IF ActualRetention < Floor THEN PayoutPct = 0
ELSE IF ActualRetention >= 1 THEN PayoutPct = 1.5
ELSE PayoutPct = 0.5 + (ActualRetention - Floor)/(1 - Floor)*0.5;
RetentionPayout = PayoutPct * RetentionVariable;

QuarterlyDraw = DrawRate * (RetentionVariable / 4);
IF Quarter IN (Q1,Q2,Q3) THEN Payout = QuarterlyDraw
ELSE Payout = MAX(0, AnnualRetentionPayout - 3*QuarterlyDraw);

ServicesBCR = PrimaryBCR * 0.5;
ServicesComm = ServicesBookings * ServicesBCR;
ChannelServicesComm = (SourcedSvcs * SourcedBCR/2) + (FulfilledSvcs * FulfilledBCR/2);

PassUpFlat = CountPassedOpps * 50;
PassUpCW = SUM(ClosedWonPassedDealValues) * 0.02;
Total = PassUpFlat + PassUpCW;
